            var displayName = "State (" + stateCode + ")";
            var properties = window.top.regionsByKey[stateCode];
            if (properties) displayName = properties.name;
            outputTitle(displayName + " " + displayLabel);
            return {
                ob: properties,
                parm: stateCode
            };
