        selObj.selectedIndex = 0;
        selObj.options[stateIdx++] = new Option("Select State", "");
        skipsInitializeLists();
        for(var stateKey in window.top.completeListOfCounties){
            var stateObj = window.top.completeListOfCounties[stateKey];
            //console.log("renderStateListSelector: " + stateObj.name + ") " + stateObj.counties.length + " counties");
            selObj.options[stateIdx] = new Option(stateObj.name, stateObj.key);
            if (stateObj.key == skipsBirdData.qs.state) {
                selObj.selectedIndex = stateIdx;
                stateName = stateObj.name;
            }
            stateIdx++;
        }
        return stateName;
