        selObj.options[countyIdx++] = new Option(stateOrProvince, "");
        var countyName = "(" + stateOrProvince + ")";
        var stateObj = window.top.completeListOfCounties[selectedStateKey];
        console.log("renderCountyListSelector: " + stateObj.name + ", " + selectedCounty);
        var countiesInState = stateObj.counties;
        for(var iCounty = 0; iCounty < countiesInState.length; iCounty++){
            var countyObj = countiesInState[iCounty];
            selObj.options[countyIdx] = new Option(countyObj.name, countyObj.key);
            if (countyObj.key == selectedCounty) {
                selObj.selectedIndex = countyIdx;
                countyName = countyObj.name;
            }
            countyIdx++;
        }
        if (selObj.selectedIndex == 0) selObj.selectedIndex = -1;
        return countyName;
