function skipsNav() {
    // set up opener
    var opener = document.getElementById("skipsNavOpen");
    var hamburger = document.createElement("div");
    hamburger.className = "skipsNavVeg";
    hamburger.innerHTML = "&equiv;";
    opener.innerHTML = "";
    opener.appendChild(hamburger);
    opener.onclick = openNav;
    // set up closer
    var settingsPanel = document.getElementById("skipsSettingsPanel");
    var closer = document.createElement("a");
    closer.setAttribute('href', "javascript:void(0)");
    closer.className = "navClose";
    closer.onclick = closeNav;
    closer.innerHTML = "&times;";
    settingsPanel.appendChild(closer);
    return {
        "closeNav": closeNav
    };
    function openNav() {
        settingsPanel.style.width = "100%";
        settingsPanel.style.maxWidth = "500px";
        settingsPanel.style.visibility = "visible";
    }
    function closeNav() {
        settingsPanel.style.width = "0";
        settingsPanel.style.visibility = "hidden";
    }
}

